class S3SigV4Uploader {
  final String region;
  final String bucket;
  final AwsCredentials creds;
  final http.Client _client;

  S3SigV4Uploader({
    required this.region,
    required this.bucket,
    required this.creds,
    http.Client? client,
  }) : _client = client ?? http.Client();

  Future<Uri> putObjectBytes({
    required Uint8List bytes,
    required String key,
    required String contentType,
    Map<String, String> extraHeaders = const {},
  }) async {
    final host = '$bucket.s3.$region.amazonaws.com';
    final uri = Uri.https(host, '/$key');

    final now = DateTime.now().toUtc();
    final amzDate = _toAmzDate(now);
    final dateStamp = _toDateStamp(now);

    final payloadHash = sha256.convert(bytes).toString();

    final headers = <String, String>{
      'host': host,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
      'content-type': contentType,
      ...extraHeaders,
    };

    if (creds.sessionToken != null && creds.sessionToken!.isNotEmpty) {
      headers['x-amz-security-token'] = creds.sessionToken!;
    }

    final signed = _signV4(
      method: 'PUT',
      uri: uri,
      region: region,
      service: 's3',
      headers: headers,
      payloadHash: payloadHash,
      amzDate: amzDate,
      dateStamp: dateStamp,
      accessKeyId: creds.accessKeyId,
      secretAccessKey: creds.secretAccessKey,
    );

    final reqHeaders = <String, String>{...headers, 'Authorization': signed.authorization};
    final resp = await _client.put(uri, headers: reqHeaders, body: bytes);

    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw HttpException('S3 PUT failed ${resp.statusCode}: ${resp.body}');
    }
    return uri;
  }

  _SigV4Result _signV4({
    required String method,
    required Uri uri,
    required String region,
    required String service,
    required Map<String, String> headers,
    required String payloadHash,
    required String amzDate,
    required String dateStamp,
    required String accessKeyId,
    required String secretAccessKey,
  }) {
    final canonicalUri = uri.path.isEmpty ? '/' : uri.path;

    final canonicalQuery = _canonicalQueryString(uri.queryParametersAll);

    final lowerHeaders = <String, String>{};
    for (final e in headers.entries) {
      lowerHeaders[e.key.toLowerCase()] = e.value.trim();
    }

    final sortedHeaderKeys = lowerHeaders.keys.toList()..sort();
    final canonicalHeaders = StringBuffer();
    for (final k in sortedHeaderKeys) {
      canonicalHeaders.writeln('$k:${lowerHeaders[k]}\n'.trimRight());
    }
    final signedHeaders = sortedHeaderKeys.join(';');

    final canonicalRequest = [
      method,
      canonicalUri,
      canonicalQuery,
      '${canonicalHeaders.toString()}\n',
      signedHeaders,
      payloadHash,
    ].join('\n');

    final algorithm = 'AWS4-HMAC-SHA256';
    final credentialScope = '$dateStamp/$region/$service/aws4_request';
    final stringToSign = [
      algorithm,
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(secretAccessKey, dateStamp, region, service);
    final signature = Hmac(sha256, signingKey).convert(utf8.encode(stringToSign)).toString();

    final authorization =
        '$algorithm Credential=$accessKeyId/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

    return _SigV4Result(authorization: authorization);
  }

  List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmac(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = _hmac(kDate, utf8.encode(regionName));
    final kService = _hmac(kRegion, utf8.encode(serviceName));
    final kSigning = _hmac(kService, utf8.encode('aws4_request'));
    return kSigning;
  }

  List<int> _hmac(List<int> key, List<int> msg) => Hmac(sha256, key).convert(msg).bytes;

  String _toAmzDate(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}T${two(dt.hour)}${two(dt.minute)}${two(dt.second)}Z';
  }

  String _toDateStamp(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}';
  }

  String _canonicalQueryString(Map<String, List<String>> qpAll) {
    if (qpAll.isEmpty) return '';
    final items = <MapEntry<String, String>>[];
    for (final e in qpAll.entries) {
      final key = _awsEncode(e.key);
      final values = e.value.isEmpty ? [''] : e.value;
      for (final v in values) {
        items.add(MapEntry(key, _awsEncode(v)));
