String randomKeyName({String ext = 'jpg'}) {
  final r = Random.secure();
  final bytes = List<int>.generate(16, (_) => r.nextInt(256));
  final hexStr = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
  return '$hexStr.$ext';
}